/**
 * Documentation Routes
 * Serves API, MCP, and Plugin documentation with caching and error handling
 *
 * HTML templates live in server/docs/*.html — no inline HTML in this file.
 * JSON payloads are generated by lib/ generators — no hardcoded data here.
 */

import express, { Request, Response } from 'express';
import { readFileSync } from 'fs';
import { promises as fsAsync } from 'fs';
import { resolve, join } from 'path';
import { fileURLToPath } from 'url';
import { dirname } from 'path';
import { generateOpenAPISpec } from '../lib/openapi-gen.js';
import { generateMCPSpec, generatePlatformMCPSpec } from '../lib/mcp-gen.js';
import { getPricingPayload } from '../lib/pricing-data.js';
import { docsCache } from '../lib/docs-cache.js';
import {
  isDocumentationError,
  ValidationError,
} from '../lib/docs-errors.js';

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);

const router = express.Router();

// ─── Constants ────────────────────────────────────────────────────────────────

const packageJson = JSON.parse(
  readFileSync(resolve(__dirname, '../../package.json'), 'utf-8')
);

const VERSION: string = packageJson.version || '1.0.0';
const SERVER_URL: string = process.env.SERVER_URL || 'http://localhost:3001';
const DOCS_DIR = resolve(__dirname, '../docs');

/** Baseline import count (Button component) used to normalise usage percentages */
const BUTTON_MAX_IMPORTS = 167;

// ─── Template loader ──────────────────────────────────────────────────────────

const templateCache = new Map<string, string>();

/**
 * Read an HTML template from server/docs/, replace {{VERSION}}, cache in memory.
 * Falls back to a minimal error page if the file is missing.
 */
function readTemplate(filename: string): string {
  if (templateCache.has(filename)) return templateCache.get(filename)!;

  let content: string;
  try {
    content = readFileSync(join(DOCS_DIR, filename), 'utf-8');
  } catch {
    content = `<html><body><h1>Template Not Found</h1><p>${filename} is missing from server/docs/</p></body></html>`;
  }

  const rendered = content.replace(/\{\{VERSION\}\}/g, VERSION);
  templateCache.set(filename, rendered);
  return rendered;
}

// ─── Shared helpers ───────────────────────────────────────────────────────────

function setDocsHeaders(res: Response, ttl = 300): void {
  res.set('Cache-Control', `public, max-age=${ttl}`);
  res.set('X-Content-Type-Options', 'nosniff');
  res.set('X-Frame-Options', 'SAMEORIGIN');
}

function sendCachedJSON(res: Response, data: unknown, ttl = 300): void {
  setDocsHeaders(res, ttl);
  res.setHeader('Content-Type', 'application/json; charset=utf-8');
  res.json(data);
}

function sendCachedHTML(res: Response, html: string, ttl = 3600): void {
  setDocsHeaders(res, ttl);
  res.setHeader('Content-Type', 'text/html; charset=utf-8');
  res.send(html);
}

function handleDocsError(err: unknown, res: Response): void {
  console.error('[Docs Error]:', err);

  if (isDocumentationError(err)) {
    setDocsHeaders(res);
    res.status(err.statusCode).json(err.toJSON());
  } else if (err instanceof Error) {
    setDocsHeaders(res);
    res.status(500).json({ error: err.message, code: 'INTERNAL_ERROR' });
  } else {
    setDocsHeaders(res);
    res.status(500).json({ error: 'Unknown error occurred', code: 'INTERNAL_ERROR' });
  }
}

function validateSearchQuery(query: string): string {
  if (!query || typeof query !== 'string') throw new ValidationError('Search query is required');

  const sanitized = query.trim();
  if (sanitized.length < 2) throw new ValidationError('Search query must be at least 2 characters', { length: sanitized.length });
  if (sanitized.length > 100) throw new ValidationError('Search query must not exceed 100 characters', { length: sanitized.length });
  if (/<[^>]*>|<script|<iframe|javascript:/i.test(sanitized)) throw new ValidationError('Invalid characters in search query');

  return sanitized;
}

/** Compute usage level and percentage for a component by its import count. */
function calcComponentUsage(imports: number): { percentage: number; level: string } {
  return {
    percentage: Math.min(100, (imports / BUTTON_MAX_IMPORTS) * 100),
    level: imports > 30 ? 'critical'
         : imports > 10 ? 'frequent'
         : imports > 2  ? 'moderate'
         : imports > 0  ? 'rare'
         : 'unused',
  };
}

// ─── Cache helpers ────────────────────────────────────────────────────────────

const TTL_SPEC   = 60 * 60 * 1000; // 1h — specs rarely change
const TTL_SEARCH = 10 * 60 * 1000; // 10m — search results

function getOpenAPISpec() {
  return docsCache.getOrGenerate('openapi-spec', () => generateOpenAPISpec(VERSION, SERVER_URL), TTL_SPEC);
}

function getMCPSpec() {
  return docsCache.getOrGenerate('mcp-spec', () => generateMCPSpec(), TTL_SPEC);
}

function getPlatformSpec() {
  return docsCache.getOrGenerate('platform-mcp-spec', () => generatePlatformMCPSpec(), TTL_SPEC);
}

// ─── Routes ───────────────────────────────────────────────────────────────────

router.get('/', (_req, res) => res.redirect('/docs'));
router.get('/api', (_req, res) => res.redirect('/docs'));
router.get('/plugin', (_req, res) => res.redirect('/docs'));
router.get('/plugin/mcp', (_req, res) => res.redirect('/docs'));

/**
 * GET /docs/api/spec
 * OpenAPI 3.0 Specification (JSON)
 */
router.get('/api/spec', (req: Request, res: Response) => {
  try {
    const spec = getOpenAPISpec();
    res.setHeader('X-API-Version', VERSION);
    sendCachedJSON(res, spec, 3600);
  } catch (err) {
    handleDocsError(err, res);
  }
});

