/**
 * GET /docs/search
 * Full-text search across API endpoints and MCP tools
 * Query: ?q=<term> (2–100 chars)
 */
router.get('/search', (req: Request, res: Response) => {
  try {
    const queryParam = (req.query.q as string) || '';

    if (!queryParam || queryParam.trim().length === 0) {
      sendCachedJSON(res, { results: [], query: '', message: 'Search query is required' });
      return;
    }

    const query = validateSearchQuery(queryParam).toLowerCase();
    const openAPISpec = getOpenAPISpec();
    const mcpSpec = getMCPSpec();
    const results: Array<{ type: string; title: string; description: string; url: string }> = [];

    for (const [path, methods] of Object.entries(openAPISpec.paths)) {
      for (const [method, details] of Object.entries(methods as Record<string, any>)) {
        if (!['get', 'post', 'put', 'delete', 'patch'].includes(method)) continue;
        if (
          path.toLowerCase().includes(query) ||
          details.summary?.toLowerCase().includes(query) ||
          details.description?.toLowerCase().includes(query)
        ) {
          results.push({
            type: 'endpoint',
            title: `${method.toUpperCase()} ${path}`,
            description: details.summary ?? '',
            url: `/api/docs/api#${(details.tags || [])[0] || 'api'}`,
          });
        }
      }
    }

    for (const tool of mcpSpec.tools) {
      if (tool.name.toLowerCase().includes(query) || tool.description.toLowerCase().includes(query)) {
        results.push({
          type: 'tool',
          title: tool.name,
          description: tool.description,
          url: '/api/docs/plugin/mcp',
        });
      }
    }

    sendCachedJSON(res, { results, query }, TTL_SEARCH);
  } catch (err) {
    handleDocsError(err, res);
  }
});

/**
 * GET /docs/export
 * Export OpenAPI or MCP spec as downloadable file
 * Query: ?format=openapi|mcp
 */
router.get('/export', (req: Request, res: Response) => {
  try {
    const format = (req.query.format as string) || 'openapi';

    if (!['openapi', 'mcp'].includes(format)) {
      throw new ValidationError('Invalid export format. Use: openapi, mcp', { format });
    }

    if (format === 'openapi') {
      const spec = getOpenAPISpec();
      setDocsHeaders(res, 3600);
      res.setHeader('Content-Type', 'application/json; charset=utf-8');
      res.setHeader('Content-Disposition', 'attachment; filename="openapi.json"');
      res.json(spec);
    } else {
      const spec = getMCPSpec();
      setDocsHeaders(res, 3600);
      res.setHeader('Content-Type', 'application/json; charset=utf-8');
      res.setHeader('Content-Disposition', 'attachment; filename="mcp-spec.json"');
      res.json(spec);
    }
  } catch (err) {
    handleDocsError(err, res);
  }
});

/**
 * GET /docs/api/components-usage
 * Component usage metrics — requires scripts/reports/component-usage.json
 * Generate with: node scripts/analyze-components.js --json
 */
router.get('/api/components-usage', (_req: Request, res: Response) => {
  const metricsPath = join(process.cwd(), 'scripts', 'reports', 'component-usage.json');

  fsAsync.readFile(metricsPath, 'utf-8')
    .then(data => {
      const metrics = JSON.parse(data);
      sendCachedJSON(res, {
        success: true,
        generatedAt: new Date().toISOString(),
        summary: metrics.metadata,
        distribution: metrics.categorized,
        components: (metrics.components || []).map((c: any) => ({
          name: c.name,
          path: c.path,
          imports: c.imports,
          category: c.category,
          usage: calcComponentUsage(c.imports),
        })),
        topComponents: (metrics.components || []).slice(0, 10),
        orphaned: (metrics.components || []).filter((c: any) => c.imports === 0),
      }, 3600);
    })
    .catch((err: Error) => {
      setDocsHeaders(res);
      res.status(404).json({
        error: 'Component metrics not available',
        suggestion: 'Run: node scripts/analyze-components.js --json',
        details: err.message,
      });
    });
});

/**
 * GET /docs/api/component/:name
 * Usage details for a specific component by name (case-insensitive)
 */
router.get('/api/component/:name', (req: Request, res: Response) => {
  const { name } = req.params;

  // Sanitize: alphanumeric + hyphens only
  if (!/^[a-zA-Z0-9-]+$/.test(name)) {
    setDocsHeaders(res);
    res.status(400).json({ error: 'Invalid component name' });
    return;
  }

  const metricsPath = join(process.cwd(), 'scripts', 'reports', 'component-usage.json');

  fsAsync.readFile(metricsPath, 'utf-8')
    .then(data => {
      const metrics = JSON.parse(data);
      const component = (metrics.components || []).find(
        (c: any) => c.name.toLowerCase() === name.toLowerCase()
      );

      if (!component) {
        setDocsHeaders(res);
        res.status(404).json({ error: `Component '${name}' not found` });
        return;
      }

      sendCachedJSON(res, {
        success: true,
        component: { ...component, usage: calcComponentUsage(component.imports) },
      }, 3600);
    })
    .catch((err: Error) => {
      setDocsHeaders(res);
      res.status(500).json({ error: 'Failed to read component metrics', details: err.message });
    });
});

export default router;
